var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"부르셨어요, 주인님?","JPN":"ご主人様、お呼びでしょうか？","ENG":"Did you call me, Master?","TWN":"您叫我了嗎，主人？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"욕조에 물을 받아드릴까요? 아니면 식사부터 하시겠어요? 그것도 아니면......","JPN":"お風呂にしますか？　お食事にしますか？　それとも……","ENG":"Would you like to bathe? Or would you like your dinner first? Or...","TWN":"要不要為您準備洗澡水？還是想先用餐？或者……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......고통 없는 편안한 숙면을 선사해드릴까요?","JPN":"……痛みのない、安らかな睡眠をできるようにいたしましょうか。","ENG":"Would you like some peaceful, painless sleep?","TWN":"……給您安詳舒適的睡眠，好不好？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_15"},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"릴리의 분위기를 이용한 졸음 깨우기 농담이었습니다.","JPN":"リリーならではの、居眠り防止用ジョークでした。","ENG":"That was Lily's joke, to help you get rid of daytime sleepiness.","TWN":"這是莉莉為了讓主人醒來的玩笑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"메이드장님은 주인님에게 웃음을 드리는 것이 메이드로서의 가장 큰 기쁨이라고 했어요.","JPN":"メイド長は、ご主人様に笑いを届けるのがメイドとして最大の喜びだと言いました。","ENG":"The Chief Maid said as your maids we should strive to put a smile on your face.","TWN":"女僕長大人說過，能讓主人微笑是女僕最大的幸福。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그래서 저도 농담을 연구해보고 있습니다만, 번번히 실패만 하는 것 같네요.","JPN":"それで私もジョークを研究していますが、いつも失敗ばかりですね。","ENG":"That's why I've been studying jokes. It seems none of the ones I've discovered so far have worked.","TWN":"所以我也嘗試研究了玩笑話，卻每次都以失敗告終。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네? 억지로 웃기보단 같이 공감하며 웃고 싶으시다고요?","JPN":"はい？無理やり笑うよりは、一緒に共感しながら笑いたい？","ENG":"Huh? You want to laugh with me?","TWN":"嗯？您說與其刻意逗笑別人，不如兩個人產生共鳴一起笑？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......저는 메이드지만, 본디 사냥꾼으로 길러진 몸.","JPN":"……私はメイドですが、本来ハンターとして育てられました。","ENG":"I'm a maid now, but I was originally trained to be a hunter.","TWN":"……我雖然是女僕，但從小就被當作獵人長大。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"사적인 감정을 철저히 배제한 채 명령만을 수행하기 위해 만들어진 몸입니다.","JPN":"私的感情を徹底的に排除し、命令だけを遂行するために作られた身です。","ENG":"I only know how to follow orders; I don't know how to feel.","TWN":"我的私人感情早已被消除，我的身體只是一個執行命令的空殼罷了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"주인님과 똑같은 감정을 느끼기엔 이미 늦어버린 걸지도 모르죠.","JPN":"ご主人様と同じような感情を覚えるには、もう遅いかもしれません。","ENG":"It might be too late for me to share my feelings with you.","TWN":"我可能再也不能感受到和主人相同的感情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"방금 발언은 메이드답지 못했군요. 주인님에게 이런 사적인 고민을 털어놓다니...... 수치사 각 날카롭습니다.","JPN":"今の発言はメイドらしくありませんでした。ご主人様にこんな私的な悩みを打ち明けるなんて……恥ずかしいです。","ENG":"I'm sorry, I wasn't being professional. I should never have confided in my employer. It was FUBB.","TWN":"剛才的發言有失我作為女僕的身份。竟然對主人說出如此私人的事情……太羞愧了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......네?","JPN":"……はい？","ENG":"... Pardon?","TWN":"……啊？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"잠시만 얼굴을 마주보고 있어 달라니...... 원하신다면 그렇게 하겠습니다만......","JPN":"少しだけ向かい合っていてほしいなんて……ご希望でしたらそういたしますが……","ENG":"You want to stay face-to-face with me for a while? Okay, if you wish...","TWN":"您希望我看著你的臉……既然這是您的請求……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"후후.","JPN":"ふふ。","ENG":"Hah hah.","TWN":"嘻嘻。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"죄송합니다. 그렇게 웃으시는 모습은 처음 봐서 저도 모르게.","JPN":"すみません。そうやって笑う姿は初めて見ましたので、つい。","ENG":"I'm sorry, but I've never seen you smiling so brightly before.","TWN":"不好意思。我第一次看到您這樣的笑容，不自覺地就。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"네, 그렇군요. 공감이라는 건 사실 그리 어려운 게 아니었네요.","JPN":"ええ、そうですね。共感というのはそんなに難しいことではなかったんですね。","ENG":"You're right. Sharing feelings isn't as difficult as I thought.","TWN":"哦，原來如此。原來共鳴也不是很困難的事情。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"좋아하는 사람의 미소만 봐도, 이렇게 함께 웃을 수 있는데 말입니다.","JPN":"好きな人の笑顔を見るだけで、こうして一緒に笑えるのに。","ENG":"I didn't know just seeing someone you like smile could make you also smile.","TWN":"看見喜歡的人笑，也可以這樣一起歡笑。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"하지만 전 주인님을 위해 봉사하는 메이드.","JPN":"ですが、私はご主人様に仕えるメイド。","ENG":"But I'm your maid.","TWN":"但我是為主人服務的女僕。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"고작 미소만으로 주인님을 기쁘게 해드리기엔, 아직 많이 부족하겠죠.","JPN":"笑顔でご主人様を喜ばせるには、まだまだ至らないと思います。","ENG":"Just putting a smile on your face isn't good enough.","TWN":"除了用微笑給主人帶來快樂，還有很多事情要做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"언젠가 제 미소가 주인님의 미소가 될 수 있도록......","JPN":"いつか私の笑顔が、ご主人様の笑顔になれますように……","ENG":"I want my smiles to be just as infectious as yours.","TWN":"希望總有一天，我的微笑會成為主人的微笑……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"릴리가 주인님을 좋아하는 만큼 주인님도 릴리를 좋아할 수 있도록, 앞으로도 분발하겠습니다.","JPN":"リリーがご主人様のことを好きな分だけ、ご主人様もリリーを好きになるように、これからも頑張ります。","ENG":"I'll try my best as your maid, so one day you'll be as fond of me as I'm fond of you.","TWN":"我會更加努力，我要讓主人喜歡上莉莉，就像莉莉喜歡主人一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};